        function refreshDevices() {
            console.log('[REFRESH] refreshDevices called');
            return apiGet('/api/v1/devices').then(function(result) {
                console.log('[REFRESH] API response:', result);
                if (!result.success) {
                    allDevices = [];
                    renderDevices([]);
                    return;
                }
                allDevices = result.data || [];
                renderDevices(allDevices);
                // Update dashboard counters
                var online = allDevices.filter(function(d) { return d.online; }).length;
                var countEl = document.getElementById('devCount');
                if (countEl) countEl.textContent = allDevices.length;
                var onlineEl = document.getElementById('devOnline');
                if (onlineEl) onlineEl.textContent = online;
                var totalEl = document.getElementById('devTotal');
                if (totalEl) totalEl.textContent = allDevices.length;
                // Update PTZ & advanced device dropdowns
                refreshPtzDeviceList();
                refreshAdvancedDeviceSelectors();
            }).catch(function(e) {
                console.warn('Failed to refresh devices:', e);
            });
        }
        function renderDevices(devices) {
            var tb = document.getElementById('deviceTable');
            if (!tb) return;
            if (!devices.length) {
                tb.innerHTML = '<tr><td colspan="8" style="text-align:center;color:#6e7681">暂无设备</td></tr>';
                return;
            }
            var html = devices.map(function(d) {
                var sourceBadge = d.source === 'sadp'
                    ? '<span class="badge sadp">SADP</span>'
                    : '<span class="badge manual">手动</span>';
                var onlineBadge = d.online
                    ? '<span class="badge online">在线</span>'
                    : '<span class="badge offline">离线</span>';
                var actions = buildDeviceActions(d);
                return '<tr>'
                    + '<td>' + sourceBadge + '</td>'
                    + '<td>' + (d.mac || '--') + '</td>'
                    + '<td>' + (d.ip || '--') + '</td>'
                    + '<td>' + (d.gateway || '--') + '</td>'
                    + '<td>' + (d.name || d.device_name || '--') + '</td>'
                    + '<td>' + (d.model || '--') + '</td>'
                    + '<td>' + onlineBadge + '</td>'
                    + '<td>' + actions + '</td>'

