function refreshDevices() {
    console.log('[REFRESH] refreshDevices called');
    var btn = document.getElementById('btnDiscover');
    var spinner = document.getElementById('discoverSpinner');
    if (spinner) spinner.style.display = 'inline-block';
    return apiPost('/api/v1/devices/refresh', {}).then(function(result) {
        console.log('[REFRESH] API response:', result);
        if (spinner) spinner.style.display = 'none';
        if (!result.success) {
            allDevices = [];
            renderDevices([]);
            return;
        }
        allDevices = result.data || [];
        renderDevices(allDevices);
        // Update dashboard counters
        var online = allDevices.filter(function(d) { return d.status === '在线' || d.status === '已连接'; }).length;
        var countEl = document.getElementById('devCount');
        if (countEl) countEl.textContent = allDevices.length;
        var onlineEl = document.getElementById('devOnline');
        if (onlineEl) onlineEl.textContent = online;
        var totalEl = document.getElementById('devTotal');
        if (totalEl) totalEl.textContent = allDevices.length;
        // Update PTZ & advanced device dropdowns
        refreshPtzDeviceList();
        refreshAdvancedDeviceSelectors();
    }).catch(function(e) {
        if (spinner) spinner.style.display = 'none';
        console.warn('Failed to refresh devices:', e);
    });
}
function loadDevicesQuick() {
    // 快速获取设备列表（无状态，不ping）
    return apiGet('/api/v1/devices').then(function(result) {
        if (result.success) {
            allDevices = result.data || [];
            renderDevices(allDevices);
        }
    });
}

