                    addLog('success', 'SADP 发现 ' + data.count + ' 台设备: ' + data.message);
                    showToast('success', data.message);
                    refreshDevices();
                } else {
                    addLog('error', '发现失败: ' + (data.message || '未知错误'));
                    showToast('error', data.message || '发现失败');
                }
            }).catch(function(e) {
                addLog('error', 'SADP 发现异常: ' + e.message);
                showToast('error', 'SADP 发现异常: ' + e.message);
