                "model": dev.get("model", ""),
                "gateway": dev.get("gateway", ""),
                "subnet_mask": dev.get("subnet_mask", ""),
                "has_credentials": True,
                "status": "离线",
            }

    for sadp in discovered:
        mac = _normalize_mac(sadp.get("mac", "") or "")
